func solve(grid [][]int64, x int64, y int64, k int64) [][]int64 {
    if k <= 1 {
        return grid
    }
    half := k / 2
    for r := int64(0); r < half; r++ {
        topRow := x + r
        bottomRow := x + k - 1 - r
        for j := y; j < y+k; j++ {
            grid[topRow][j], grid[bottomRow][j] = grid[bottomRow][j], grid[topRow][j]
        }
    }
    return grid
}
