func solve(grid [][]int64, x int64, y int64, k int64) [][]int64 {
    // Create a deep copy of the grid to avoid modifying the original
    newGrid := make([][]int64, len(grid))
    for i := range grid {
        newGrid[i] = make([]int64, len(grid[i]))
        copy(newGrid[i], grid[i])
    }

    // Iterate over the rows in the submatrix and reverse them
    for i := int64(0); i < k/2; i++ {
        row1 := x + i
        row2 := x + k - 1 - i

        // Swap the rows within the submatrix columns
        for j := y; j < y+k; j++ {
            newGrid[row1][j], newGrid[row2][j] = newGrid[row2][j], newGrid[row1][j]
        }
    }

    return newGrid
}
